import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminTaxonomyForm = () => {
  const { type } = useParams(); // 'theme' or 'tag'
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  
  const [formData, setFormData] = useState({
    id: '',
    name: '',
    nameAr: ''
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.id || !formData.name) return toast.error("ID and Name are required");

    const payload = type === 'theme' 
      ? { Theme_ID: formData.id, Theme_Name: formData.name, Theme_Name_In_Arabic: formData.nameAr, type }
      : { Tag_ID: formData.id, Tag_Name: formData.name, Tag_Name_In_Arabic: formData.nameAr, type };

    setLoading(true);
    try {
      await AdminService.upsertTaxonomy(payload);
      toast.success(`${type} registered`);
      navigate('/admin/taxonomy');
    } catch (err) { toast.error("Save failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-8 animate-in slide-in-from-bottom-4 duration-700">
      <button onClick={() => navigate('/admin/taxonomy')} className="flex items-center gap-2 text-gray-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-colors">
        <ArrowLeft size={14} /> Back to Taxonomy
      </button>

      <form onSubmit={handleSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] p-10 space-y-8">
        <h2 className="text-2xl font-black italic uppercase">Register New <span className="text-primary">{type}</span></h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-[9px] font-black uppercase text-gray-500 ml-1">Unique {type} ID</label>
            <input 
              value={formData.id} onChange={e => setFormData({...formData, id: e.target.value})}
              placeholder={type === 'theme' ? "THEME001" : "TAG001"}
              className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-white outline-none focus:border-primary font-bold transition-all"
            />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black uppercase text-gray-500 ml-1">Display Name (EN)</label>
            <input 
              value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})}
              className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-white outline-none focus:border-primary font-bold transition-all"
            />
          </div>
          <div className="space-y-1 md:col-span-2">
            <label className="text-[9px] font-black uppercase text-gray-500 ml-1">Arabic Translation</label>
            <input 
              value={formData.nameAr} onChange={e => setFormData({...formData, nameAr: e.target.value})}
              dir="rtl"
              className="w-full bg-white/5 border border-white/10 p-4 rounded-2xl text-white outline-none focus:border-primary font-bold transition-all text-right"
            />
          </div>
        </div>

        <button type="submit" disabled={loading} className="bg-primary text-black px-12 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-white transition-all flex items-center gap-2">
          <Save size={16}/> {loading ? 'Processing...' : 'Commit to Archive'}
        </button>
      </form>
    </div>
  );
};
